/** Params grouped by effect family (built once at module load). */
export const FM9_PARAMS_BY_FAMILY: Readonly<Record<string, readonly Param[]>> = (() => {
  const map: Record<string, Param[]> = {};
  for (const p of FM9_PARAMS) {
    (map[p.family] ??= []).push(p);
  }
  return Object.freeze(map);
})();

